import{_ as i,c as e,o as l,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"플랫폼 및 통합: 다중 모델 AI 구성","description":"다중 AI 플랫폼(Anthropic, OpenAI, Google, Copilot)을 구성하고 관리하는 방법을 배우고, 자동 장애 조치 메커니즘과 지능형 모델 선택을 마스터하세요.","frontmatter":{"title":"플랫폼 및 통합: 다중 모델 AI 구성","sidebarTitle":"AI 계정 연결","subtitle":"플랫폼 및 통합: 다중 모델 AI 구성","description":"다중 AI 플랫폼(Anthropic, OpenAI, Google, Copilot)을 구성하고 관리하는 방법을 배우고, 자동 장애 조치 메커니즘과 지능형 모델 선택을 마스터하세요.","order":40},"headers":[],"relativePath":"ko/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"ko/code-yeongyu/oh-my-opencode/platforms/index.md"}'),s={name:"ko/code-yeongyu/oh-my-opencode/platforms/index.md"};function t(n,a,r,p,d,h){return l(),e("div",null,[...a[0]||(a[0]=[o(`<h1 id="플랫폼-및-통합" tabindex="-1">플랫폼 및 통합 <a class="header-anchor" href="#플랫폼-및-통합" aria-label="Permalink to &quot;플랫폼 및 통합&quot;">​</a></h1><p>이 장에서는 여러 AI 제공업체(Anthropic, OpenAI, Google, GitHub Copilot 등)를 구성하고 관리하는 방법과 oh-my-opencode의 다중 모델 자동 장애 조치(fallback) 메커니즘을 소개합니다.</p><p>이 장을 완료하면 작업 유형과 사용 가능한 모델에 따라 시스템이 가장 적합한 AI 모델을 지능적으로 선택하도록 하는 방법을 마스터하고, 효율적이고 신뢰할 수 있는 다중 모델 오케스트레이션 워크플로우를 구축할 수 있습니다.</p><h2 id="이-장에서-다루는-내용" tabindex="-1">이 장에서 다루는 내용 <a class="header-anchor" href="#이-장에서-다루는-내용" aria-label="Permalink to &quot;이 장에서 다루는 내용&quot;">​</a></h2><p>이 장은 두 부분으로 나뉩니다.</p><h3 id="_1-제공업체-구성" tabindex="-1">1. <a href="./provider-setup/">제공업체 구성</a> <a class="header-anchor" href="#_1-제공업체-구성" aria-label="Permalink to &quot;1. [제공업체 구성](provider-setup/)&quot;">​</a></h3><p>다양한 AI 제공업체를 구성하는 방법을 배웁니다.</p><ul><li>Anthropic Claude (주요 오케스트레이터의 1순위 선택)</li><li>OpenAI ChatGPT (아키텍처 리뷰 전용)</li><li>Google Gemini (프론트엔드 및 미디어 분석)</li><li>GitHub Copilot (백업 제공업체)</li><li>Z.ai 코딩 계획 및 OpenCode Zen (선택적 서비스)</li></ul><p><strong>학습 내용</strong>:</p><ul><li>✅ 6개 주요 AI 제공업체 구성</li><li>✅ 빠른 설정을 위한 대화형 설치 프로그램 사용</li><li>✅ 다양한 에이전트에 가장 적합한 모델 지정</li><li>✅ 구성 문제 진단을 위한 <code>doctor</code> 명령어 사용</li></ul><p><strong>예상 소요 시간</strong>: 25-30분</p><h3 id="_2-다중-모델-전략" tabindex="-1">2. <a href="./model-resolution/">다중 모델 전략</a> <a class="header-anchor" href="#_2-다중-모델-전략" aria-label="Permalink to &quot;2. [다중 모델 전략](model-resolution/)&quot;">​</a></h3><p>모델 해결 시스템의 3단계 우선순위 메커니즘을 심층적으로 다룹니다.</p><ul><li>사용자 재정의 (정밀 제어)</li><li>제공업체 장애 조치 (자동 장애 허용)</li><li>시스템 기본값 (대체 솔루션)</li></ul><p><strong>학습 내용</strong>:</p><ul><li>✅ 모델 해결의 전체 워크플로우 이해</li><li>✅ 작업 요구사항에 따라 모델 수동 지정</li><li>✅ 제공업체 장애 조치를 활용한 시스템 견고성 향상</li><li>✅ 모델 해결 문제 진단 및 해결</li></ul><p><strong>예상 소요 시간</strong>: 30-35분</p><h2 id="권장-학습-경로" tabindex="-1">권장 학습 경로 <a class="header-anchor" href="#권장-학습-경로" aria-label="Permalink to &quot;권장 학습 경로&quot;">​</a></h2><p>이 장을 학습할 때 다음 순서를 따르는 것을 권장합니다.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[설치 완료] --&gt; B[제공업체 구성]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[다중 모델 전략]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[고급 기능]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>이 순서의 이유는?</strong></p><ol><li><strong>먼저 구성, 나중에 이해</strong>: 각 제공업체를 구성하는 방법을 먼저 배운 다음, 기본 해결 메커니즘을 이해하세요</li><li><strong>단순에서 복잡으로</strong>: 제공업체 구성은 기본 작업이고, 다중 모델 전략은 고급 개념입니다</li><li><strong>실습으로 이론 검증</strong>: 제공업체를 구성한 후 <code>doctor</code> 명령어를 사용하여 다중 모델 전략의 효과를 검증할 수 있습니다</li></ol><div class="tip custom-block"><p class="custom-block-title">빠른 시작 경로</p><p>빠르게 시작하고 싶다면 <a href="./provider-setup/">제공업체 구성</a>의 1-4단계(기본 제공업체 구성)만 완료하고, 나중에 필요에 따라 다른 내용을 학습할 수 있습니다.</p></div><h2 id="사전-요구사항" tabindex="-1">사전 요구사항 <a class="header-anchor" href="#사전-요구사항" aria-label="Permalink to &quot;사전 요구사항&quot;">​</a></h2><p>이 장을 학습하기 전에 다음을 확인하세요.</p><ul><li>✅ <a href="./../installation/">설치 및 초기 구성</a> 완료</li><li>✅ OpenCode 설치 (버전 &gt;= 1.0.150)</li><li>✅ 기본 JSON/JSONC 구성 파일 형식 이해</li><li>✅ 최소 하나의 AI 제공업체 계정 구독 (Anthropic Claude 권장)</li></ul><div class="warning custom-block"><p class="custom-block-title">제공업체 계정이 없다면?</p><p>실제로 제공업체에 연결하지 않고 구성 단계를 먼저 학습할 수 있습니다. 시스템은 OpenCode의 기본 모델을 대체 솔루션으로 사용합니다.</p></div><h2 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h2><details><summary><strong>모든 제공업체를 구성해야 하나요?</strong></summary><p>아니요. 가장 많이 사용하는 제공업체만 구성할 수 있습니다(예: Anthropic Claude만). oh-my-opencode의 제공업체 장애 조치 메커니즘이 사용 가능한 제공업체를 자동으로 사용합니다.</p><p>하지만 다중 모델 오케스트레이션의 장점을 완전히 활용하려면 최소 2-3개 제공업체를 구성하는 것을 권장합니다. 그러면 시스템이 작업 유형에 따라 가장 적합한 모델을 자동으로 선택할 수 있습니다.</p></details><details><summary><strong>제공업체 구성과 모델 해결의 차이는 무엇인가요?</strong></summary><ul><li><strong>제공업체 구성</strong>: &quot;설치 단계&quot;로, 시스템에 사용 가능한 AI 서비스를 알려주는 것</li><li><strong>모델 해결</strong>: &quot;결정 로직&quot;으로, 시스템이 각 에이전트에 어떤 제공업체를 사용할지 선택하는 방법</li></ul><p>비유: 제공업체 구성은 &quot;팀원 채용&quot;, 모델 해결은 &quot;작업 배정&quot;입니다.</p></details><details><summary><strong>구성을 언제든 수정할 수 있나요?</strong></summary><p>언제든 구성 파일을 수정할 수 있습니다.</p><ul><li>사용자 구성: <code>~/.config/opencode/oh-my-opencode.json</code></li><li>프로젝트 구성: <code>.opencode/oh-my-opencode.json</code></li></ul><p>변경 사항은 다음에 에이전트를 사용할 때 자동으로 적용됩니다. 제공업체 인증을 수정한 경우 <code>opencode auth login</code>을 실행하여 재인증해야 합니다.</p></details><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후 다음을 수행할 수 있습니다.</p><h3 id="권장-경로-ai-에이전트-팀-학습" tabindex="-1">권장 경로: AI 에이전트 팀 학습 <a class="header-anchor" href="#권장-경로-ai-에이전트-팀-학습" aria-label="Permalink to &quot;권장 경로: AI 에이전트 팀 학습&quot;">​</a></h3><p><a href="./../../advanced/ai-agents-overview/">AI 에이전트 팀: 10명 전문가 개요</a>를 계속 학습하여 전문화된 작업에 다양한 에이전트를 사용하는 방법을 이해하세요.</p><h3 id="고급-경로-심층-사용자-정의" tabindex="-1">고급 경로: 심층 사용자 정의 <a class="header-anchor" href="#고급-경로-심층-사용자-정의" aria-label="Permalink to &quot;고급 경로: 심층 사용자 정의&quot;">​</a></h3><p>기본 구성에 이미 익숙하다면 <a href="./../../advanced/advanced-configuration/">구성 심층 분석: 에이전트 및 권한 관리</a>로 건너뛰어 다음을 학습할 수 있습니다.</p><ul><li>에이전트 프롬프트 사용자 정의 방법</li><li>에이전트 권한 및 액세스 범위 설정 방법</li><li>사용자 정의 에이전트 및 카테고리 생성 방법</li></ul><h3 id="실용-경로-프로메테우스-계획-사용" tabindex="-1">실용 경로: 프로메테우스 계획 사용 <a class="header-anchor" href="#실용-경로-프로메테우스-계획-사용" aria-label="Permalink to &quot;실용 경로: 프로메테우스 계획 사용&quot;">​</a></h3><p><a href="./../../advanced/prometheus-planning/">프로메테우스 계획: 인터뷰 스타일 요구사항 수집</a>을 사용하여 실제 에이전트 협업을 통해 다중 모델 오케스트레이션의 힘을 경험하세요.</p><hr><p><strong>시작하기</strong>: <a href="./provider-setup/">제공업체 구성</a>으로 다중 모델 오케스트레이션 여정을 시작하세요!</p>`,42)])])}const g=i(s,[["render",t]]);export{u as __pageData,g as default};
